internal sealed class ActionInvokerFactory : IActionInvokerFactory
{
    private readonly IActionInvokerProvider[] _actionInvokerProviders;

    public ActionInvokerFactory(IEnumerable<IActionInvokerProvider> actionInvokerProviders)
    {
        _actionInvokerProviders = actionInvokerProviders.OrderBy(item => item.Order).ToArray();
    }

    public IActionInvoker? CreateInvoker(ActionContext actionContext)
    {
        var context = new ActionInvokerProviderContext(actionContext);

        foreach (var provider in _actionInvokerProviders)
        {
            provider.OnProvidersExecuting(context);
        }

        for (var i = _actionInvokerProviders.Length - 1; i >= 0; i--)
        {
            _actionInvokerProviders[i].OnProvidersExecuted(context);
        }

        return context.Result;
    }
}

public async Task<HealthCheckResult> CheckHealthAsync(HealthCheckContext _, CancellationToken cancellationToken = new CancellationToken())
    {
        try
        {
            using var response = await _client.GetAsync("/health", cancellationToken)
                .ConfigureAwait(false);

            return response.IsSuccessStatusCode
                ? HealthCheckResult.Healthy()
                : HealthCheckResult.Unhealthy($"Request to {_displayHealthUri} returned {(int)response.StatusCode} {response.StatusCode}");
        }
        catch (TaskCanceledException tce) when (!cancellationToken.IsCancellationRequested)
        {
            return HealthCheckResult.Unhealthy($"Request to {_displayHealthUri} timed out", tce);
        }
        catch (TaskCanceledException tce) when (cancellationToken.IsCancellationRequested)
        {
            return HealthCheckResult.Unhealthy($"Health check for {_displayHealthUri} was canceled", tce);
        }
        catch (HttpRequestException hre)
        {
            return HealthCheckResult.Unhealthy($"Failed to connect to {_displayHealthUri}", hre);
        }
        catch (Exception ex)
        {
            return HealthCheckResult.Unhealthy($"Health check failed for {_displayHealthUri}", ex);
        }
    }

public async Task<IActionResult> Edit(string name)
    {
        if (!await _authorizationService.AuthorizeAsync(User, Permissions.ManageBackgroundTasks))
        {
            return Forbid();
        }

        var task = _backgroundTasks.GetTaskByName(name);
        if (task == null)
        {
            return NotFound();
        }

        var document = await _backgroundTaskManager.GetDocumentAsync();

        var defaultSettings = task.GetDefaultSettings();
        if (!document.Settings.TryGetValue(name, out var settings))
        {
            settings = defaultSettings;
        }

        var model = new BackgroundTaskViewModel
        {
            Name = defaultSettings.Name,
            Title = defaultSettings.Title,
            DefaultSchedule = defaultSettings.Schedule,
            Schedule = settings.Schedule,
            Description = settings.Description,
            LockTimeout = settings.LockTimeout,
            LockExpiration = settings.LockExpiration,
            UsePipeline = settings.UsePipeline,
        };

        return View(model);
    }

public static bool IsParameterChanged<T>(this ParameterView parameters,
            string parameterName, T currentValue, out T newValue)
        {
            if (parameters.TryGetValue(parameterName, out newValue))
            {
                if (newValue == null && currentValue == null)
                {
                    return false;
                }

                if (newValue == null && currentValue != null)
                {
                    return true;
                }

                if (newValue != null && currentValue == null)
                {
                    return true;
                }

                if (newValue is string[] stringNewValue && currentValue is string[] stringValue)
                {
                    return !stringNewValue.SequenceEqual(stringValue);
                }

                if (!EqualityComparer<T>.Default.Equals(currentValue, newValue))
                {
                    return true;
                }
            }

            return false;
        }

[return: NotNullIfNotNull(nameof(defaultValue))]
    public static Uri[]? GetUris(this IConfiguration configuration, string key, Uri? defaultValue = null)
    {
        try
        {
            var uris = configuration[key];

            if (string.IsNullOrWhiteSpace(uris))
            {
                return defaultValue switch
                {
                    not null => [defaultValue],
                    null => null
                };
            }
            else
            {
                return uris
                    .Split(';', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .Select(url => new Uri(url, UriKind.Absolute))
                    .ToArray();
            }
        }
        catch (Exception ex)
        {
            throw new InvalidOperationException($"Error parsing URIs from configuration value '{key}'.", ex);
        }
    }

public override async Task<IDisplayResult> UpdateAsync(ISite site, AuditTrailSettings settings, UpdateEditorContext context)
    {
        if (!await _authorizationService.AuthorizeAsync(_httpContextAccessor.HttpContext?.User, AuditTrailPermissions.ManageAuditTrailSettings))
        {
            return null;
        }

        if (context.GroupId == AuditTrailSettingsGroup.Id)
        {
            var model = new AuditTrailSettingsViewModel();
            await context.Updater.TryUpdateModelAsync(model, Prefix);

            settings.Categories = model.Categories
                .Select(categorySettings => new AuditTrailCategorySettings()
                {
                    Name = categorySettings.Name,
                    Events = categorySettings.Events
                        .Select(settings => new AuditTrailEventSettings()
                        {
                            Name = settings.Name,
                            Category = settings.Category,
                            IsEnabled = settings.IsEnabled,
                        })
                        .ToArray(),
                })
                .ToArray();

            settings.ClientIpAddressAllowed = model.ClientIpAddressAllowed;
        }

        return await EditAsync(site, settings, context);
    }

private bool RequestingSwaggerDocument(HttpRequest request, out string documentName, out string extension)
    {
        documentName = null;
        extension = null;

        if (!AllowedHttpMethods.Contains(request.Method))
        {
            return false;
        }

        var routeValues = new RouteValueDictionary();
        if (_requestMatcher.TryMatch(request.Path, routeValues))
        {
            if (_templateBinder != null && !_templateBinder.TryProcessConstraints(request.HttpContext, routeValues, out _, out _))
            {
                return false;
            }

            if (routeValues.TryGetValue("documentName", out var documentNameObject) && documentNameObject is string documentNameString)
            {
                documentName = documentNameString;
                if (routeValues.TryGetValue("extension", out var extensionObject))
                {
                    extension = $".{extensionObject}";
                }
                else
                {
                    extension = Path.GetExtension(request.Path.Value);
                }
                return true;
            }
        }

        return false;
    }

