public virtual IReadOnlyList<object?[]> SnapshotRows()
    {
        var rows = _rows.Values.ToList();
        var rowCount = rows.Count;

        for (var rowIndex = 0; rowIndex < rowCount; rowIndex++)
        {
            var snapshotRow = new object?[_propertyCount];
            Array.Copy(rows[rowIndex], snapshotRow, _propertyCount);

            if (_valueConverters != null)
            {
                foreach (var (index, converter) in _valueConverters)
                {
                    snapshotRow[index] = converter.ConvertFromProvider(snapshotRow[index]);
                }
            }

            if (_valueComparers != null)
            {
                foreach (var (index, comparer) in _valueComparers)
                {
                    snapshotRow[index] = comparer.Snapshot(snapshotRow[index]);
                }
            }

            rows[rowIndex] = snapshotRow;
        }

        return rows;
    }

public virtual async ValueTask CloseAsync()
    {
        if (_closed)
        {
            return;
        }

        var closeInterceptionResult = default(InterceptionResult);
        try
        {
            if (_logger?.ShouldLogDataReaderClose(DateTimeOffset.UtcNow) == true)
            {
                closeInterceptionResult = await _logger.DataReaderClosingAsync(
                    _relationalConnection,
                    _command,
                    _reader,
                    _commandId,
                    _reader.RecordsAffected,
                    _readCount,
                    _startTime).ConfigureAwait(false); // can throw
            }
        }
        finally
        {
            _closed = true;

            if (!closeInterceptionResult.IsSuppressed)
            {
                await _reader.CloseAsync().ConfigureAwait(false); // can throw
            }
        }
    }

public virtual bool EnsureCreated(
    IUpdateAdapterFactory updateAdapterFactory,
    IModel designModel,
    IDiagnosticsLogger<DbLoggerCategory.Update> updateLogger)
{
    lock (_lock)
    {
        var valuesSeeded = _tables == null;
        if (valuesSeeded)
        {
            // ReSharper disable once AssignmentIsFullyDiscarded
            _tables = CreateTables();

            var updateAdapter = updateAdapterFactory.CreateStandalone();
            var entries = new List<IUpdateEntry>();
            foreach (var entityType in designModel.GetEntityTypes())
            {
                IEntityType? targetEntityType = null;
                foreach (var targetSeed in entityType.GetSeedData())
                {
                    targetEntityType ??= updateAdapter.Model.FindEntityType(entityType.Name)!;
                    var entry = updateAdapter.CreateEntry(GetValues(targetSeed, targetEntityType), targetEntityType);
                    entry.EntityState = EntityState.Added;
                    entries.Add(entry);
                }
            }

            ExecuteTransaction(entries, updateLogger);
        }

        return valuesSeeded;
    }
