public PredicateBuilder<TResult> HandleInner<TException>(Func<TException, bool> predicate)
        where TException : Exception
    {
        Guard.NotNull(predicate);

        return Add(outcome => HandleInner(outcome.Exception, predicate));

        static bool HandleInner(Exception? exception, Func<TException, bool> predicate)
        {
            if (exception is AggregateException aggregate)
            {
                foreach (var innerException in aggregate.Flatten().InnerExceptions)
                {
                    if (HandleNested(predicate, innerException))
                    {
                        return true;
                    }
                }
            }

            return HandleNested(predicate, exception);

            static bool HandleNested(Func<TException, bool> predicate, Exception? current)
            {
                if (current is null)
                {
                    return false;
                }
                else if (current is TException exceptionOfT)
                {
                    return predicate(exceptionOfT);
                }

                return HandleNested(predicate, current.InnerException);
            }
        }
    }

private void UpdateFilteredOptions()
        {
            var newList = GetOptionItems();

            // quick equality check by comparing labels; ensures we only update
            // UI when actual contents change. avoids unnecessary renders when the
            // data source is reassigned with the same items, or when input value
            // is set programmatically to the same string.
            var newLabels = newList.Select(x => x.Label).ToArray();
            if (_lastFilteredLabels.SequenceEqual(newLabels))
            {
                // still update state flags in case IsOptionsZero changed
                _isOptionsZero = newLabels.Length == 0;
                return;
            }

            _filteredOptions = newList;
            _isOptionsZero = _filteredOptions.Count == 0;
            _lastFilteredLabels = newLabels;

            if (_isFocused && !_isOptionsZero)
            {
                _ = OpenPanel();
            }

            // only render when content actually changed
            StateHasChanged();

            // refresh overlay component so the DOM reflects the new items
            _overlayTrigger?.GetOverlayComponent()?.RefreshComponentState();
        }

private static MongoClient CreateMongoClient(
    this IServiceProvider serviceProvider,
    string connectionName,
    MongoDBSettings mongoDbSettings,
    Action<MongoClientSettings>? configureClientSettings)
{
    mongoDbSettings.ValidateSettings(connectionName);

    var clientSettings = MongoClientSettings.FromConnectionString(mongoDbSettings.ConnectionString);

    if (!mongoDbSettings.DisableTracing)
    {
        clientSettings.ClusterConfigurator = cb => cb.Subscribe(new DiagnosticsActivityEventSubscriber());
    }

    configureClientSettings?.Invoke(clientSettings);

    clientSettings.LoggingSettings ??= new LoggingSettings(serviceProvider.GetService<ILoggerFactory>());

    var aspireVersion = typeof(MongoDBSettings).Assembly.GetName().Version?.ToString();
    if (clientSettings.LibraryInfo != null)
    {
        clientSettings.LibraryInfo = new LibraryInfo($"{clientSettings.LibraryInfo.Name}|aspire", $"{clientSettings.LibraryInfo.Version}|{aspireVersion}");
    }
    else
    {
        clientSettings.LibraryInfo = new LibraryInfo("aspire", aspireVersion);
    }

    return new MongoClient(clientSettings);
}

private static Dictionary<string, string> Load(string path)
    {
        if (!File.Exists(path))
        {
            return new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        }

        var json = File.ReadAllText(path);
        if (string.IsNullOrWhiteSpace(json))
        {
            return new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        }

        var parsed = JsonNode.Parse(json)?.AsObject();
        if (parsed is null)
        {
            return new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        }

        // Flatten nested JSON to colon-separated keys
        var flat = JsonFlattener.FlattenJsonObject(parsed);

        var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
        foreach (var kvp in flat)
        {
            var value = kvp.Value?.ToString();
            if (value is not null)
            {
                result[kvp.Key] = value;
            }
        }

        return result;
    }

private void InstrumentConsumption(DateTimeOffset startTime, DateTimeOffset endTime, ConsumeResult consumeResult, string? errorType)
    {
        if (this.options.Traces)
        {
            PropagationContext propagationContext = consumeResult.Headers != null
                ? OpenTelemetryConsumeResultExtensions.ExtractPropagationContext(consumeResult.Headers)
                : default;

            using Activity? activity = this.StartReceiveActivity(propagationContext, startTime, consumeResult.TopicPartitionOffset, consumeResult.Key);
            if (activity != null)
            {
                if (errorType != null)
                {
                    activity.SetStatus(ActivityStatusCode.Error);
                    if (activity.IsAllDataRequested)
                    {
                        activity.SetTag(SemanticConventions.AttributeErrorType, errorType);
                    }
                }

                activity.SetEndTime(endTime.UtcDateTime);
            }
        }

        if (this.options.Metrics)
        {
            TimeSpan duration = endTime - startTime;
            RecordReceive(consumeResult.TopicPartitionOffset!.TopicPartition, duration, errorType);
        }
    }

public static string NavigateUrl(string alias, string path, string parameters)
        {
            string querystring = "";
            string fragment = "";

            if (!string.IsNullOrEmpty(path) && !path.StartsWith("/")) path = "/" + path;

            if (!string.IsNullOrEmpty(parameters))
            {
                (string urlparameters, querystring, fragment) = ParseParameters(parameters);
                if (!string.IsNullOrEmpty(urlparameters))
                {
                    path += (path.EndsWith("/") ? "" : "/") + $"{Constants.UrlParametersDelimiter}/{urlparameters.Substring(1)}";
                }
            }

            // build url
            var uriBuilder = new UriBuilder
            {
                Path = !string.IsNullOrEmpty(alias)
                    ? (!string.IsNullOrEmpty(path)) ? $"{alias}{path}": $"{alias}"
                    : $"{path}",
                Query = querystring,
                Fragment = fragment
            };

            return uriBuilder.Uri.PathAndQuery;
        }

private static string GenerateRelativeUniquePath(List<AutorouteEntry> entries, string path, AutoroutePart context)
    {
        var version = 1;
        var unversionedPath = path;

        var versionSeparatorPosition = path.LastIndexOf('-');
        if (versionSeparatorPosition > -1 && int.TryParse(path[versionSeparatorPosition..].TrimStart('-'), out version))
        {
            unversionedPath = path[..versionSeparatorPosition];
        }

        while (true)
        {
            // Unversioned length + separator char + version length.
            var quantityCharactersToTrim = unversionedPath.Length + 1 + version.ToString().Length - AutoroutePart.MaxPathLength;
            if (quantityCharactersToTrim > 0)
            {
                unversionedPath = unversionedPath[..^quantityCharactersToTrim];
            }

            var versionedPath = $"{unversionedPath}-{version++}";
            if (IsRelativePathUnique(entries, versionedPath, context))
            {
                var entry = entries.FirstOrDefault(e => e.ContainedContentItemId == context.ContentItem.ContentItemId);
                entry.Path = versionedPath;

                return versionedPath;
            }
        }
    }

public async Task SaveDraftAsync<T>(string key, T data, DraftOptions options = null)
        {
            options ??= new DraftOptions { Key = key };
            if (!options.Enabled) return;

            // Cancel previous pending save
            CancelPendingSave(key);

            // Create new delayed save task
            var cts = new CancellationTokenSource();
            lock (_lockObject)
            {
                _pendingSaves[key] = cts;
            }

            try
            {
                await Task.Delay(options.DelayMilliseconds, cts.Token);
                await SaveDraftImmediateAsync(key, data, options);
            }
            catch (TaskCanceledException)
            {
                // Delay was cancelled, ignore
            }
            finally
            {
                lock (_lockObject)
                {
                    if (_pendingSaves.TryGetValue(key, out var existingCts) && existingCts == cts)
                    {
                        _pendingSaves.Remove(key);
                        cts.Dispose();
                    }
                }
            }
        }

private IEntityFinder Finder([DynamicallyAccessedMembers(IEntityType.DynamicallyAccessedMemberTypes)] Type type)
    {
        var entityType = Model.FindEntityType(type);
        if (entityType == null)
        {
            if (Model.IsShared(type))
            {
                throw new InvalidOperationException(CoreStrings.InvalidSetSharedType(type.ShortDisplayName()));
            }

            var findSameTypeName = Model.FindSameTypeNameWithDifferentNamespace(type);
            //if the same name exists in your entity types we will show you the full namespace of the type
            if (!string.IsNullOrEmpty(findSameTypeName))
            {
                throw new InvalidOperationException(
                    CoreStrings.InvalidSetSameTypeWithDifferentNamespace(type.DisplayName(), findSameTypeName));
            }

            throw new InvalidOperationException(CoreStrings.InvalidSetType(type.ShortDisplayName()));
        }

        if (entityType.FindPrimaryKey() == null)
        {
            throw new InvalidOperationException(CoreStrings.InvalidSetKeylessOperation(type.ShortDisplayName()));
        }

        return DbContextDependencies.EntityFinderFactory.Create(entityType);
    }

public Task OnHandledOutcomeAsync(Outcome<T> outcome, ResilienceContext context)
    {
        EnsureNotDisposed();

        var task = Task.CompletedTask;

        lock (_lock)
        {
            SetLastHandledOutcome_NeedsLock(outcome);

            _behavior.OnActionFailure(_circuitState, out var shouldBreak);

            // Circuit state handling
            // HalfOpen - open the circuit again
            // Closed - break the circuit if the behavior indicates it
            // Open, Isolated - a failure call result may arrive when the circuit is open,
            // if it was placed before the circuit broke. We take no action beyond tracking
            // the metric; we do not want to duplicate-signal onBreak; we do not want to extend time for which the circuit is broken.
            // We do not want to mask the fact that the call executed (as replacing its result with a Broken/IsolatedCircuitException would do).

            if (_circuitState == CircuitState.HalfOpen || (_circuitState == CircuitState.Closed && shouldBreak))
            {
                task = OpenCircuitFor_NeedsLock(outcome, _breakDuration, manual: false, context);
            }
        }

        return ExecuteScheduledTaskAsync(task, context);
    }

public virtual TValue Next<TValue>(Func<long> getNewLowValue)
    {
        var newValue = GetNextValue();

        // If the chosen value is outside of the current block then we need a new block.
        // It is possible that other threads will use all of the new block before this thread
        // gets a chance to use the new value, so use a while here to do it all again.
        while (newValue.Low >= newValue.High)
        {
            _semaphoreSlim.Wait();
            try
            {
                // Once inside the lock check to see if another thread already got a new block, in which
                // case just get a value out of the new block instead of requesting one.
                if (newValue.High == _currentValue.High)
                {
                    var newCurrent = getNewLowValue();
                    newValue = new HiLoValue(newCurrent, newCurrent + _blockSize);
                    _currentValue = newValue;
                }
                else
                {
                    newValue = GetNextValue();
                }
            }
            finally
            {
                _semaphoreSlim.Release();
            }
        }

        return ConvertResult<TValue>(newValue);
    }

public async Task<bool> HasDraftAsync(string key, DraftOptions options = null)
        {
            options ??= new DraftOptions { Key = key };
            if (!options.Enabled) return false;

            var provider = options.StorageProvider ?? _defaultStorageProvider;
            var exists = await provider.ExistsAsync(key);

            if (!exists) return false;

            // If version check is enabled, need to validate version
            if (options.EnableVersionCheck)
            {
                var json = await provider.LoadAsync(key);
                if (string.IsNullOrEmpty(json))
                    return false;

                try
                {
                    var versionData = JsonSerializer.Deserialize<DraftData<object>>(json);
                    return versionData?.Version == options.Version;
                }
                catch
                {
                    return false;
                }
            }

            return true;
        }

public static List<OtlpSpanDto> GetSpanDtosFromOtlpData(IList<OtlpResourceSpansJson>? resourceSpans)
    {
        var spans = new List<OtlpSpanDto>();

        if (resourceSpans is null)
        {
            return spans;
        }

        foreach (var resourceSpan in resourceSpans)
        {
            var resource = CreateResourceFromOtlpJson(resourceSpan.Resource);

            if (resourceSpan.ScopeSpans is null)
            {
                continue;
            }

            foreach (var scopeSpan in resourceSpan.ScopeSpans)
            {
                var scopeName = scopeSpan.Scope?.Name;

                if (scopeSpan.Spans is null)
                {
                    continue;
                }

                foreach (var span in scopeSpan.Spans)
                {
                    spans.Add(new OtlpSpanDto(span, resource, scopeName));
                }
            }
        }

        return spans;
    }

