public static string StructuredLogsUrl(string? resource = null, string? logLevel = null, string? filters = null, string? traceId = null, string? spanId = null, long? logEntryId = null)
    {
        var url = $"/{StructuredLogsBasePath}";
        if (resource != null)
        {
            url += $"/resource/{Uri.EscapeDataString(resource)}";
        }
        if (logLevel != null)
        {
            url = AddQueryString(url, "logLevel", logLevel);
        }
        if (filters != null)
        {
            // Filters contains : and + characters. These are escaped when they're not needed to,
            // which makes the URL harder to read. Consider having a custom method for appending
            // query string here that uses an encoder that doesn't encode those characters.
            url = AddQueryString(url, "filters", filters);
        }
        if (traceId != null)
        {
            url = AddQueryString(url, "traceId", traceId);
        }
        if (spanId != null)
        {
            url = AddQueryString(url, "spanId", spanId);
        }
        if (logEntryId != null)
        {
            url = AddQueryString(url, "logEntryId", logEntryId.Value.ToString(CultureInfo.InvariantCulture));
        }

        return url;
    }

public static (List<TResult> items, string message) GetLimitFromEndWithSummary<T, TResult>(
    List<T> values,
    int totalValues,
    int limit,
    string itemName,
    string pluralItemName,
    Func<T, TResult> convertToDto,
    Func<TResult, int> estimateTokenSize)
{
    Debug.Assert(totalValues >= values.Count, "Total values should be large or equal to the values passed into the method.");

    var trimmedItems = values.Count <= limit
        ? values
        : values[^limit..];

    var currentTokenCount = 0;
    var serializedValuesCount = 0;
    var dtos = trimmedItems.Select(i => convertToDto(i)).ToList();

    // Loop backwards to prioritize the latest items.
    for (var i = dtos.Count - 1; i >= 0; i--)
    {
        var obj = dtos[i];
        var tokenCount = estimateTokenSize(obj);

        if (currentTokenCount + tokenCount > MaximumListTokenLength)
        {
            break;
        }

        serializedValuesCount++;
        currentTokenCount += tokenCount;
    }

    // Trim again with what fits in the token limit.
    dtos = dtos[^serializedValuesCount..];

    return (dtos, GetLimitSummary(totalValues, dtos.Count, itemName, pluralItemName));
}

public static bool TryParseConsoleTimestamp(string text, [NotNullWhen(true)] out TimestampParserResult? result)
    {
        // Regex is cached inside the method.
        var match = GenerateRfc3339RegEx().Match(text);

        if (match.Success)
        {
            var span = text.AsSpan();

            ReadOnlySpan<char> content;
            if (match.Index + match.Length >= span.Length)
            {
                content = "";
            }
            else
            {
                content = span[(match.Index + match.Length)..];

                // Trim whitespace added by logging between timestamp and content.
                if (char.IsWhiteSpace(content[0]))
                {
                    content = content.Slice(1);
                }
            }

            result = new(content.ToString(), DateTimeOffset.Parse(match.ValueSpan, CultureInfo.InvariantCulture));
            return true;
        }

        result = default;
        return false;
    }

private static bool CanAccessFile(string filepath)
        {
            // ensure file is not locked by another process
            int retries = 60;
            int sleep = 2;
            int attempts = 0;
            FileStream stream = null;

            bool locked = true;
            while (attempts < retries && locked)
            {
                try
                {
                    if (File.Exists(filepath))
                    {
                        stream = File.Open(filepath, FileMode.Open, FileAccess.Read, FileShare.None);
                        locked = false;
                    }
                    else
                    {
                        locked = false;
                    }
                }
                catch // file is locked by another process
                {
                    Thread.Sleep(sleep * 1000); // wait
                }
                finally
                {
                    stream?.Close();
                }
                attempts += 1;
            }
            if (locked)
            {
                Console.WriteLine("File Locked: " + filepath);
            }

            return !locked;
        }

